i tried to create a custom m2m widget but i get TypeError: coercing to Unicode: need string or buffer, NoneType found

```
class T1FkWidget(ForeignKeyWidget):
    def clean(self, value, row):
        try:
            val =  self.model.objects.get(t1= value)
        except self.model.DoesNotExist:
            val = self.model.objects.create(t1=value)
        return val

    def render(self, value, row):
        return value.t1

class T3M2MWidget(ManyToManyWidget):
    def __init__(self, model, m2mfield, separator=u', ', field='pk', defaults=None, create=False, *args, **kwargs):
        self.model = model
        self.m2mfield = m2mfield
        self.separator = separator
        self.field = field
        self.defaults = defaults
        self.create = create
        super(T3M2MWidget, self).__init__(self.model, separator=self.separator, field=self.field, *args, **kwargs)

    def clean(self, value):
        values = filter(None, value.split(self.separator))
        if self.create:
            results = [self.model.objects.get_or_create(defaults=self.defaults, **{self.field: v})[0] for v in values]
            caller_frame = inspect.stack()[1].frame
            caller_args = inspect.getargvalues(caller_frame)
            data = caller_args.locals['data']
            this_row = data[self.field]
            existing_obj = self.model.objects.get(**{self.field: this_row})
            existing_related = getattr(existing_obj, self.m2mfield).all()
            existing_related_objs = [self.model.objects.get(**{self.field: r}) for r in existing_related]
            combined_results = results + list(set(existing_related_objs) - set(results))
            return combined_results
        else:
            try:
                val = super(T3M2MWidget, self).clean(value)
            except ObjectDoesNotExist:
                model_name = self.model.__name__
                error = u"Imported data includes nonexistant %s(s) (%s) " \
                        u"\nThis model does not support creating a new %s when importing data." \
                        % (model_name, value, model_name)
                return None
            else:
                return val

class T2Resource(resources.ModelResource):
    t1 = fields.Field(attribute='t1', column_name='T1',
                      widget=T1FkWidget(T1, 't1'))

    t3 = fields.Field(attribute=u't3', column_name=u't3',
                      widget=T3M2MWidget(T3, 't3'))

    class Meta:
        model = T2
        fields = (
            'id', 't2', 't1', 't3',
        )

class T2Admin(ImportExportModelAdmin, ImportExportActionModelAdmin):
    list_display = ['t2','t1',]
    resource_class = T2Resource
