    technologies = models.ManyToManyField(Technology, related_name='technology_stacks')


class TechnologyProfileSerializer(serializers.ModelSerializer):
    user_id = RelayIdField()
    name = serializers.CharField()

    class Meta:
        model = TechnologyProfile
        fields = ('id', 'name', 'user_id')


class TechnologySerializer(serializers.ModelSerializer):
    user_id = RelayIdField()
    profile = TechnologyProfileSerializer(many=False)

    class Meta:
        model = Technology
        fields = '__all__'


class TechnologyStackSerializer(serializers.ModelSerializer):
    technologies = TechnologySerializer(many=True)

    class Meta:
        model = TechnologyStack
        read_only_fields = ('id',)
        fields = '__all__'


class CreateTechnologyProfile(SerializerMutation):
    class Meta:
        serializer_class = TechnologyProfileSerializer


class CreateTechnology(SerializerMutation):
    class Meta:
        serializer_class = TechnologySerializer


class CreateTechnologyStack(SerializerMutation):
    class Meta:
        serializer_class = TechnologyStackSerializer


class Mutation(ObjectType):
    create_technology = CreateTechnology.Field()
    create_technology_profile = CreateTechnologyProfile.Field()
    create_technology_stack = CreateTechnologyStack.Field()
```

